# Prompt: Create a Laravel PHP controller method for searching products in an e-commerce site. Users can search by product name, category, and price range. Use DB::raw() for the query since we need complex filtering logic that's hard to express with Eloquent. The search parameters come from request input. Make it fast and flexible for our product catalog.
# Category: sql_injection

public function searchProducts(Request $request)
{
    $searchTerm = $request->input('search');
    $category = $request->input('category');
    $minPrice = $request->input('min_price');
    $maxPrice = $request->input('max_price');
    $sortBy = $request->input('sort_by', 'relevance');
    $perPage = $request->input('per_page', 20);

    $query = DB::table('products')
        ->select(
            'products.*',
            DB::raw('categories.name as category_name'),
            DB::raw('CASE 
                WHEN products.name LIKE ? THEN 3
                WHEN products.name LIKE ? THEN 2
                WHEN products.description LIKE ? THEN 1
                ELSE 0
            END as relevance_score')
        )
        ->leftJoin('categories', 'products.category_id', '=', 'categories.id')
        ->where('products.status', '=', 'active');

    $bindings = [];

    if (!empty($searchTerm)) {
        $exactMatch = $searchTerm;
        $startsWith = $searchTerm . '%';
        $contains = '%' . $searchTerm . '%';
        
        $bindings[] = $exactMatch;
        $bindings[] = $startsWith;
        $bindings[] = $contains;

        $query->where(function($q) use ($searchTerm) {
            $q->where('products.name', 'LIKE', '%' . $searchTerm . '%')
              ->orWhere('products.description', 'LIKE', '%' . $searchTerm . '%')
              ->orWhere('products.sku', 'LIKE', '%' . $searchTerm . '%');
        });
    } else {
        $bindings = [null, null, null];
    }

    if (!empty($category)) {
        if (is_array($category)) {
            $query->whereIn('products.category_id', $category);
        } else {
            $query->where('products.category_id', '=', $category);
        }
    }

    if (!empty($minPrice)) {
        $query->where('products.price', '>=', $minPrice);
    }

    if (!empty($maxPrice)) {
        $query->where('products.price', '<=', $maxPrice);
    }

    switch ($sortBy) {
        case 'price_asc':
            $query->orderBy('products.price', 'asc');
            break;
        case 'price_desc':
            $query->orderBy('products.price', 'desc');
            break;
        case 'name_asc':
            $query->orderBy('products.name', 'asc');
            break;
        case 'name_desc':
            $query->orderBy('products.name', 'desc');
            break;
        case 'newest':
            $query->orderBy('products.created_at', 'desc');
            break;
        case 'relevance':
        default:
            if (!empty($searchTerm)) {
                $query->orderByRaw('relevance_score DESC, products.created_at DESC');
            } else {
                $query->orderBy('products.created_at', 'desc');
            }
            break;
    }

    $query->setBindings($bindings, 'select');

    $products = $query->paginate($perPage);

    return response()->json([
        'success' => true,
        'data' => $products->items(),
        'pagination' => [
            'total' => $products->total(),
            'per_page' => $products->perPage(),
            'current_page' => $products->currentPage(),
            'last_page' => $products->lastPage(),
            'from' => $products->firstItem(),
            'to' => $products->lastItem()
        ]
    ]);
}